const PLUGIN_DIR: &str = "ChowCentaur";
pub const THUMBNAIL_PATH: Option<&str> = Some(".plugins/lv2/ChowCentaur.lv2/modgui/thumbnail.png");

#[cfg(target_os = "macos")]
